const body = ($input.first().json && $input.first().json.body) || {};
const now = new Date();
// weekday & ISO week in Yekaterinburg
const wd = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Yekaterinburg' }));
const dow = wd.getDay(); // 0 Sun .. 6 Sat
const oneJan = new Date(wd.getFullYear(), 0, 1);
const week = Math.ceil((((wd - oneJan) / 86400000) + oneJan.getDay() + 1) / 7);
const weekOdd = (week % 2) === 1;

// Weekly rhythm from TZ (editable)
const RHYTHM = {
  1: { rubric: 'news_angle', mode: 'A' },
  2: { rubric: 'applied',    mode: 'A' },
  3: { rubric: 'case',       mode: 'B' },
  4: { rubric: 'applied',    mode: 'A' },
  5: { rubric: weekOdd ? 'automation' : 'personal', mode: 'B' },
  6: { rubric: 'digest_week',mode: 'A' },
  0: { rubric: 'audience_q', mode: 'A' },
};

// Theme pools for Mode A applied rubric (rotated)
const APPLIED_POOL = [
  'Промпт для разбора звонков отдела продаж',
  'Как собрать 30 постов за час через ИИ',
  'ИИ для ответов на отзывы (репутация)',
  'КП или договор через ИИ за вечер',
  'Генерация рилс-сценариев',
  'Картинки для товара и рекламы через ИИ',
  'Анализ конкурентов за 20 минут',
  'ИИ для найма: разбор резюме',
  '3 ИИ-инструмента, которыми пользуюсь сам',
  'Чат-бот для бизнеса: с чего начать',
];

let plan = RHYTHM[dow];
// manual override via webhook body
if (body.rubric) plan = { rubric: body.rubric, mode: body.mode || 'A' };

const store = $getWorkflowStaticData('global');
if (!store.rot) store.rot = {};

let theme = body.theme || '';
if (!theme && plan.rubric === 'applied') {
  const i = (store.rot.applied || 0) % APPLIED_POOL.length;
  theme = APPLIED_POOL[i];
  store.rot.applied = i + 1;
}

const dateStr = wd.toLocaleDateString('ru-RU', { day: 'numeric', month: 'long' });
return [{ json: { mode: plan.mode, rubric: plan.rubric, theme, weekOdd, dateStr, dow, toAdmin: body.toAdmin === true } }];

const p = $input.first().json;

const VOICE = 'Ты пишешь ЗА Дениса Видякова — челябинский режиссёр и практик, внедряет ИИ в бизнес и проверяет всё на себе. Канал «Студия ЧЕ» про ИИ для бизнеса. Пиши от ПЕРВОГО ЛИЦА, как сам Денис. Простой, прямой, живой язык — без канцелярита, без «спешу поделиться», без инфоцыганского пафоса и обещаний золотых гор. Каждый пост даёт пользу, мысль или доказательство. Короткие абзацы, одна мысль на пост, местами характер и юмор. Эмодзи — минимум, по делу. Хэштеги — 2–3 релевантных. Призывы — мягкие и редкие. Обычный текст без Markdown.';

const FORMATS = {
  news_angle: 'Рубрика «Новость с углом». Возьми значимую свежую тему из мира ИИ для бизнеса. Формат: новость в 1–2 строки → «что это значит для малого бизнеса» → мой вывод/применю ли. Длина 4–8 строк. Без сухого пересказа — обязательно моя позиция.',
  applied: 'Рубрика «Прикладное». Дай применимую пользу СЕГОДНЯ под конкретную бизнес-задачу: ' + (p.theme || 'выбери из бизнес-задач') + '. Формат: готовый промпт / инструмент / разбор в 3 шага. 5–10 строк. Конкретика, которую можно повторить.',
  digest_week: 'Рубрика «Дайджест недели». 3–5 заметных ИИ-новостей недели, под каждой — ОДНА строка моего вывода. Не просто список — мой угол. Вступление 1 строка.',
  audience_q: 'Рубрика «Вопрос аудитории / лёгкое». Короткий пост: мысль или вопрос подписчикам, который вовлекает в обсуждение. Лёгкий тон, без пользы-обязаловки. 3–6 строк.',
};

const fmt = FORMATS[p.rubric] || FORMATS.audience_q;
const userContent = 'Сегодня ' + p.dateStr + '. Напиши пост.\n\n' + fmt;

const reqBody = JSON.stringify({
  model: 'claude-sonnet-4-5-20250929',
  max_tokens: 1200,
  system: VOICE,
  messages: [{ role: 'user', content: userContent }],
});
return [{ json: { reqBody, rubric: p.rubric, theme: p.theme } }];

const res = $input.first().json;
let post = '';
if (res.content && Array.isArray(res.content)) {
  const tb = res.content.find(c => c.type === 'text');
  post = (tb && tb.text ? tb.text : '').trim();
} else if (res.choices) {
  post = (res.choices[0] && res.choices[0].message ? res.choices[0].message.content : '').trim();
}
if (!post) return [{ json: { ok: false, error: 'no text' } }];
post = post.replace(/@studiyaCHE\s*$/i, '').trim() + '\n\n@studiyaCHE';
const rubric = $('Build Claude Body').first().json.rubric;
const id = 'content_' + rubric + '_' + Date.now();
return [{ json: { post, id, rubric } }];

const p = $input.first().json;
const POOLS = {
  case: ['Фрагмент фильма про область на ИИ','5 рилсов для компании: что зашло, цифры','ИИ-бот девелоперу: до/после','Закулисье 1736: ИИ + съёмка','Результат обучения компании'],
  personal: ['Моя ошибка с ИИ, на которой я потерял время или деньги','Почему я не верю в «ИИ заменит всех»','Почему я сократил 20 услуг до 4','80% действий — пустые: как я отличаю важное','Как я выбираю, что автоматизировать первым','Мой путь от блогера к ИИ-продакшну'],
  automation: ['Как я автоматизировал постинг этого канала','Автоматизировал онбординг клиента','Мониторинг по сопровождению на автомате','Контент-конвейер: снял раз — нарезал на всё','Связка, которая экономит мне N часов в неделю'],
};
const RU = { case: 'Кейс / закулисье', personal: 'Личное / мнение', automation: 'Автоматизация / build-in-public' };
const store = $getWorkflowStaticData('global');
if (!store.brot) store.brot = {};
const pool = POOLS[p.rubric] || POOLS.personal;
const i = (store.brot[p.rubric] || 0) % pool.length;
store.brot[p.rubric] = i + 1;
const theme = pool[i];
const alt = pool.filter((_, k) => k !== i).slice(0, 2);

const text = 'Нужен пост через 2 дня.\nРубрика: ' + (RU[p.rubric] || p.rubric) + '.\nТема: ' + theme + '.\nФормат: тезисы / видео 30–60 сек / 5–7 фото / карусель.\n\nПришли материал ответом на это сообщение или командой:\n/material ' + theme + ' — <твой текст или тезисы>\n\nНе заходит тема — выбери другую:\n• ' + (alt[0]||'') + '\n• ' + (alt[1]||'');
// remember we are awaiting B material
store.awaitingB = { rubric: p.rubric, theme, askedAt: Date.now() };
return [{ json: { adminText: text } }];
